import PropTypes from 'prop-types'
import React from 'react'
import type { ISudokuCoreContext } from './context'
import { SudokuCoreContextType } from './context'
import { reducer } from './reducer'
import type { ISudokuCoreState } from './state'
import { initSudokuCoreState } from './state'

export interface ISudokuCoreContextProviderProps {
  /**
   * Initial context data.
   */
  initialState?: Partial<ISudokuCoreState>
  /**
   * Descendant elements.
   */
  children: React.ReactNode
}

export const SudokuCoreContextProvider: React.FC<ISudokuCoreContextProviderProps> = props => {
  const { children, initialState } = props
  const [state, dispatch] = React.useReducer(reducer, initialState, initSudokuCoreState)

  const context: ISudokuCoreContext = React.useMemo(() => ({ state, dispatch }), [state, dispatch])
  return <SudokuCoreContextType.Provider value={context}>{children}</SudokuCoreContextType.Provider>
}

SudokuCoreContextProvider.propTypes = {
  initialState: PropTypes.any,
  children: PropTypes.node.isRequired,
}

SudokuCoreContextProvider.displayName = 'SudokuCoreContextProvider'
