import { SudokuCreator } from '@algorithm.ts/sudoku'

const creators: Record<number, SudokuCreator> = {}

/**
 * Get sudoku creator
 * @param SUDOKU_SIZE_SQRT
 * @returns
 */
export const getSudokuCreator = (SUDOKU_SIZE_SQRT: number): SudokuCreator => {
  let creator = creators[SUDOKU_SIZE_SQRT]
  if (creator === undefined) {
    creator = new SudokuCreator({ childMatrixSize: SUDOKU_SIZE_SQRT })
    creators[SUDOKU_SIZE_SQRT] = creator
  }
  return creator
}
