import type { ISudokuCoreState } from '@kyokuya/react-game-sudoku-core'
import type { IStorage } from '@kyokuya/react-storage'
import { usePersisDataEffect } from '@kyokuya/react-storage'

const persistKeys: ReadonlyArray<keyof ISudokuCoreState> = [
  'SUDOKU_SIZE_SQRT',
  'difficulty',
  'radix',
  'score',
  'puzzle',
  'solution',
  'instructions',
  'activatedCell',
  'usedTimeRef',
]

export const usePersistSudokuStateEffect = (
  storage: IStorage<Partial<ISudokuCoreState>> | null,
  state: ISudokuCoreState,
): void => {
  usePersisDataEffect<ISudokuCoreState>(storage, state, persistKeys, [state.usedTimeRef.current])
}
